import { z } from "zod";

const UserSchema = z.object({
  id: z.string(),
  name: z.string(),
});

type User = z.infer<typeof UserSchema>;

async function getUser(): Promise<User> {
  const data: unknown = await fetch("/api/user").then((r) => r.json());
  return UserSchema.parse(data);
}
